import{_ as a,o as n,c as t,a2 as o}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Integracion entre contextos","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/ddd/06-integracion-entre-contextos.md","filePath":"full-stack/arquitectura/ddd/06-integracion-entre-contextos.md","lastUpdated":1782521464000}'),i={name:"full-stack/arquitectura/ddd/06-integracion-entre-contextos.md"};function s(r,e,l,c,d,p){return n(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="integracion-entre-contextos" tabindex="-1">Integracion entre contextos <a class="header-anchor" href="#integracion-entre-contextos" aria-label="Permalink to &quot;Integracion entre contextos&quot;">​</a></h1><p>Los bounded contexts no viven aislados. Necesitan intercambiar informacion sin perder autonomia.</p><h2 id="formas-de-integracion" tabindex="-1">Formas de integracion <a class="header-anchor" href="#formas-de-integracion" aria-label="Permalink to &quot;Formas de integracion&quot;">​</a></h2><ul><li>Llamadas sincronas por API.</li><li>Eventos asincronos.</li><li>Lecturas replicadas.</li><li>Ficheros o cargas batch.</li><li>Bases compartidas solo en casos muy controlados.</li></ul><h2 id="api-sincronica" tabindex="-1">API sincronica <a class="header-anchor" href="#api-sincronica" aria-label="Permalink to &quot;API sincronica&quot;">​</a></h2><p>Util cuando necesitas respuesta inmediata.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Learning -&gt; Catalog: GET /courses/{id}</span></span></code></pre></div><p>Riesgo: acoplamiento temporal. Si Catalog cae, Learning puede fallar.</p><h2 id="eventos" tabindex="-1">Eventos <a class="header-anchor" href="#eventos" aria-label="Permalink to &quot;Eventos&quot;">​</a></h2><p>Utiles para comunicar hechos.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CoursePublished</span></span>
<span class="line"><span>StudentEnrolled</span></span>
<span class="line"><span>InvoicePaid</span></span></code></pre></div><p>Riesgo: consistencia eventual y necesidad de idempotencia.</p><h2 id="anti-corruption-layer" tabindex="-1">Anti-corruption layer <a class="header-anchor" href="#anti-corruption-layer" aria-label="Permalink to &quot;Anti-corruption layer&quot;">​</a></h2><p>Una capa anticorrupcion traduce modelos externos al lenguaje interno.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>External CRM Customer</span></span>
<span class="line"><span>  -&gt; CustomerTranslator</span></span>
<span class="line"><span>  -&gt; SupportAccount</span></span></code></pre></div><p>Evita que conceptos externos contaminen tu dominio.</p><h2 id="shared-kernel" tabindex="-1">Shared kernel <a class="header-anchor" href="#shared-kernel" aria-label="Permalink to &quot;Shared kernel&quot;">​</a></h2><p>Un shared kernel comparte una parte pequena del modelo entre contextos.</p><p>Debe ser pequeno, estable y gobernado con cuidado. Si crece demasiado, se convierte en acoplamiento peligroso.</p><h2 id="published-language" tabindex="-1">Published language <a class="header-anchor" href="#published-language" aria-label="Permalink to &quot;Published language&quot;">​</a></h2><p>Cuando un contexto publica contratos estables:</p><ul><li>API REST.</li><li>Eventos.</li><li>Schemas.</li><li>Documentacion.</li></ul><p>Los consumidores dependen de ese lenguaje publicado, no del modelo interno.</p><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>Cada integracion tiene owner y contrato.</li><li>Los eventos son idempotentes.</li><li>Los modelos externos se traducen.</li><li>No se comparten tablas internas.</li><li>La consistencia eventual se comunica al producto.</li></ul>`,25)])])}const g=a(i,[["render",s]]);export{h as __pageData,g as default};
